// src/services/api.js
const axios = require('axios');
const BASE = process.env.REACT_APP_API_URL || 'http://localhost:3000';

const BASE_URL_USERS =  "http://localhost:5000/api/users";
const BASE_URL_FUNDS =  "http://localhost:5000/api/funds";
const BASE_URL_TOKENS = "http://localhost:5000/api/tokens";
const DEFAULT_USER_CERT = "govUserTom";

function buildUrl(baseUrl, path, query = {}) {
  const url = new URL(`${baseUrl}${path}`);
  Object.entries(query).forEach(([key, value]) => {
    if (value !== undefined && value !== null && value !== "") {
      url.searchParams.set(key, value);
    }
  });
  return url.toString();
}

function normalizeResponse(payload) {
  if (payload && typeof payload === "object" && payload.response) {
    return payload.response;
  }
  return payload;
}

async function request(baseUrl, path, options = {}) {
  const { method = "GET", query = {}, body, headers = {}, ...rest } = options;
  const url = buildUrl(baseUrl, path, query);

  const reqOptions = {
    method,
    headers: {
      ...(body !== undefined ? { "Content-Type": "application/json" } : {}),
      ...headers,
    },
    ...(body !== undefined ? { body: JSON.stringify(body) } : {}),
    ...rest,
  };

  const res = await fetch(url, reqOptions);

  let payload = null;
  try {
    payload = await res.json();
  } catch {
    payload = null;
  }

  if (!res.ok) {
    const err = normalizeResponse(payload) || {};
    const error = new Error(err.error || err.message || res.statusText || "Request failed");
    error.status = res.status;
    throw error;
  }

  return normalizeResponse(payload);
}

async function requestWithFallback(baseUrl, paths, options = {}) {
  let lastError;
  for (const path of paths) {
    try {
      return await request(baseUrl, path, options);
    } catch (err) {
      lastError = err;
      if (err?.status !== 404) throw err;
    }
  }
  throw lastError;
}

const makeGet = (baseUrl) => (path, query) => request(baseUrl, path, { method: "GET", query });
const makePost = (baseUrl) => (path, body) => request(baseUrl, path, { method: "POST", body });

export const getUserCert = () => localStorage.getItem("userCert") || DEFAULT_USER_CERT;

const getUsers = makeGet(BASE_URL_USERS);
const postUsers = makePost(BASE_URL_USERS);

// Donor — { userCert, donorId, name, email, alias }
export const donorApi = {
  getAll:   ()          => requestWithFallback(BASE_URL_USERS, ["/allDonors", "/allDonor", "/donors"], { query: { userCert: getUserCert() } }),
  getOne:   (donorId)   => getUsers("/donor", { userCert: getUserCert(), donorId }),
  register: (data)      => postUsers("/donor", { userCert: getUserCert(), ...data }),
  registerDonor: (data) => axios.post(`${BASE}/api/users/donor`, data),
  getDonor: (data) => axios.post(`${BASE}/api/users/getDonor`, data),
  getAllDonors: (data) => axios.post(`${BASE}/api/users/getAllDonors`, data),
};

// NGO — { userCert, ngoId, name, regNo, address, contact, description }
export const ngoApi = {
  getAll:   ()          => requestWithFallback(BASE_URL_USERS, ["/allNGOs", "/allNGO", "/ngos"], { query: { userCert: getUserCert() } }),
  getOne:   (ngoId)     => getUsers("/ngo", { userCert: getUserCert(), ngoId }),
  register: (data)      => postUsers("/ngo", { userCert: getUserCert(), ...data }),
  registerNGO: (data) => axios.post(`${BASE}/api/users/ngo`, data),
  getNGO: (data) => axios.post(`${BASE}/api/users/getNGO`, data),
  getAllNGOs: (data) => axios.post(`${BASE}/api/users/getAllNGOs`, data),
  createFund: (data) => axios.post(`${BASE}/api/funds`, data),
  getAllFunds: (data) => axios.post(`${BASE}/api/funds/getAll`, data),
};

// Bank — { userCert, bankId, name, branch, ifscCode }
export const bankApi = {
  getAll:   ()          => requestWithFallback(BASE_URL_USERS, ["/allBanks", "/allBank", "/banks"], { query: { userCert: getUserCert() } }),
  getOne:   (bankId)    => getUsers("/bank", { userCert: getUserCert(), bankId }),
  register: (data)      => postUsers("/bank", { userCert: getUserCert(), ...data }),
  registerBank: (data) => axios.post(`${BASE}/api/users/bank`, data),
  getBank: (data) => axios.post(`${BASE}/api/users/getBank`, data),
  getAllBanks: (data) => axios.post(`${BASE}/api/users/getAllBanks`, data),
};

// Gov User — { userCert, govUserId, name, email, designation }
export const govUserApi = {
  getAll:   ()          => requestWithFallback(BASE_URL_USERS, ["/allGovUser", "/govUser"], { query: { userCert: getUserCert() } }),
  getOne:   (govUserId) => getUsers("/govUser", { userCert: getUserCert(), govUserId }),
  register: (data)      => postUsers("/govUser", { userCert: getUserCert(), ...data }),
  registerUser: (data) => axios.post(`${BASE}/api/users/register`, data),
  login: (data) => axios.post(`${BASE}/api/users/login`, data),
};

const getFunds = makeGet(BASE_URL_FUNDS);
const postFunds = makePost(BASE_URL_FUNDS);

// Fund — { userCert, fundId, ngoId, title, purpose, fundTarget }
export const fundApi = {
  getAll:              ()            => getFunds("/", { userCert: getUserCert() }),
  getOne:              (fundId)      => getFunds("/", { userCert: getUserCert(), fundId }),
  getAllByNGO:         (ngoId)       => getFunds("/ngo", { userCert: getUserCert(), ngoId }),
  getAllDonationsByDonor: (donorId)  => getFunds("/donations", { userCert: getUserCert(), donorId }),
  create:              (data)        => postFunds("/", { userCert: getUserCert(), ...data }),
  donate:              (fundId, data)=> postFunds(`/${fundId}/donate`, { userCert: getUserCert(), ...data }),
  addExpense:          (fundId, data)=> postFunds(`/${fundId}/expense`, { userCert: getUserCert(), ...data }),
  close:               (fundId)      => postFunds(`/${fundId}/close`, { userCert: getUserCert(), fundId }),
  create: (data) => axios.post(`${BASE}/api/funds`, data),
  getAll: (data) => axios.post(`${BASE}/api/funds/getAll`, data),
  donate: (data) => {
    const { fundId, ...rest } = data;
    return axios.post(`${BASE}/api/funds/${fundId}/donate`, rest);
  },
};

const getTokens = makeGet(BASE_URL_TOKENS);
const postTokens = makePost(BASE_URL_TOKENS);

// Token — { userCert, tokenId, amount, bankId, ownerId, ngoId, toId }
export const tokenApi = {
  issue:          (data)    => postTokens("/", { userCert: getUserCert(), ...data }),
  transfer:       (data)    => postTokens("/transfer", { userCert: getUserCert(), ...data }),
  redeem:         (data)    => postTokens("/redeem", { userCert: getUserCert(), ...data }),
  getByBank:      (bankId)  => getTokens("/bank", { userCert: getUserCert(), bankId }),
};

module.exports = {
  donorApi,
  ngoApi,
  bankApi,
  govUserApi,
  getUserCert: () => axios.get(`${BASE}/api/users/cert`),
  fundApi,
};
